# search occurrences containing both 'تجب' or 'توجب' and 'قبل' or 'ما قبلها' etc
def contains_tokens(nf, toks):
    return all(tok in nf for tok in toks)

toks_sets = [
    ['تجب','قبل'], 
    ['تج','قبل'], 
    ['توجب','قبل'],
    ['تجِب','قبل'],
    ['توبة','تجب','قبل'],
]
matches = []
for h in hadiths:
    for field in ('hadithTxt','Matn'):
        if field in h and h[field]:
            nf = normalize_ar(h[field])
            for toks in toks_sets:
                if contains_tokens(nf, toks):
                    matches.append((h,field,h[field], nf))
                    break
len(matches)

seq_tokens = norm_snip.split()
ordered_matches = []
for h in hadiths:
    for field in ('hadithTxt','Matn'):
        if field in h and h[field]:
            nf = normalize_ar(h[field])
            idx = 0
            found = True
            start_pos = -1
            prev_pos = -1
            for tok in seq_tokens:
                pos = nf.find(tok, prev_pos+1)
                if pos == -1:
